import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;
import org.owasp.esapi.ESAPI;
import org.owasp.esapi.codecs.HTMLEntityCodec;

public class XSSSafeServlet extends HttpServlet {
    protected void doGet(HttpServletRequest request, HttpServletResponse response)
            throws ServletException, IOException {
        String userInput = request.getParameter("input");
        PrintWriter out = response.getWriter();

        // Encode user input to prevent XSS
        HTMLEntityCodec codec = new HTMLEntityCodec();
        String encodedUserInput = codec.encode(userInput);

        out.println("<html><body>");
        out.println("<h1>Hello " + encodedUserInput + "!</h1>");
        out.println("</body></html>");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
